msg.statusCode = 500;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
msg.payload = JSON.stringify({
  ok: false,
  error: (msg.error && msg.error.message) || 'Error al consultar SQL Server'
});
return msg;

msg._res = msg.res;
const cuit = (msg.req.query.cuit || '').replace(/[^0-9]/g, '');
if (!cuit) {
  msg.statusCode = 400;
  msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
  msg.payload = JSON.stringify({ ok: false, error: 'Falta parámetro cuit' });
  return [null, msg];
}
msg.payload = `SELECT TOP 5  OC, FECHAACTUAL, FECHAENTREGA, nom_PROVEEDOR, CUIT, ESTADO,  DESCRIPCION,DETALLE AS NOMBRE_OC, NOMBREMONEDA,
               total_doc AS  btotal_doc, '' AS NUMREQ,Observaciones AS DETALLE 
               FROM V_EZI_PROV_ORDENCOMPRA_ENC 
               WHERE CUIT = '${cuit}'
               ORDER BY FECHAACTUAL DESC;`;
return [msg, null];

msg._res = msg.res;
const oc = (msg.req.params.oc || '').replace(/[^0-9A-Za-z\-]/g, '');
if (!oc) {
  msg.statusCode = 400;
  msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
  msg.payload = JSON.stringify({ ok: false, error: 'Falta OC' });
  return [null, msg];
}
msg.payload = `SELECT OC, NUMEROITEM AS NRO_ITEM,
                  (NOM_PRODUCTO + ' - ' + DESCRIPCION) AS DETALLE,
                  UNI_MED, CANTIDAD, PU, BONIFICACION,
                  TOTAL_ITEM, IVATASA, fechaentrega, MEMO
              FROM V_EZI_ORDENDECOMPRA0
              WHERE OC = '${oc}'
              ORDER BY NRO_ITEM ASC`;
return [msg, null];

msg._res = msg.res;
const oc = (msg.req.query.oc || '').replace(/[^0-9A-Za-z\-]/g, '');
if (!oc) {
  msg.statusCode = 400;
  msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
  msg.payload = JSON.stringify({ ok: false, error: 'Falta parámetro oc' });
  return [null, msg];
}
msg.payload = `SELECT
    enc.CONSTANCIA          AS nro_constancia,
    CAST(enc.ID AS varchar(36)) AS id_constancia,
    enc.FECHAACTUAL,
    enc.DETALLE             AS detalle_interno,
    enc.subtotal_doc,
    enc.totalConstancia,
    enc.monConstancia,
    enc.nom_proveedor,
    (SELECT TOP 1 ISNULL(d.NOM_PRODUCTO,'') + CASE WHEN ISNULL(d.MEMO,'') <> '' THEN ' — ' + d.MEMO ELSE '' END
     FROM V_EZI_PROV_CONST_SC_DET d
     WHERE d.constancia = enc.CONSTANCIA
     ORDER BY d.NUMEROITEM) AS descripcion,
    (SELECT TOP 1 cf.NUMEROFAC
     FROM V_EZI_CONSTANCIA_FACTURA cf
     WHERE cf.ID_CONST = enc.ID) AS factura_existente,
    (SELECT TOP 1 cf.IMPORTEFACT
     FROM V_EZI_CONSTANCIA_FACTURA cf
     WHERE cf.ID_CONST = enc.ID) AS importe_factura_existente
FROM V_EZI_PROV_CONST_SC_ENC enc
WHERE enc.numeroOC = '${oc}'
ORDER BY enc.FECHAACTUAL DESC`;
return [msg, null];

msg.res = msg._res;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
msg.payload = JSON.stringify(msg.payload || []);
return msg;

node.error('Constancias SQL error: ' + (msg.error && msg.error.message));
msg.res = msg._res;
msg.statusCode = 500;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
msg.payload = JSON.stringify({ ok: false, error: (msg.error && msg.error.message) || 'Error al consultar constancias' });
return msg;

const b = msg.req.body || {};

// Guardar para stages siguientes
msg._factura = b;

// Validar campos obligatorios
const required = ['staging_id', 'proveedor_cuit', 'proveedor_nombre', 'numerodocumento', 'fecha_emision', 'total'];
const missing = required.filter(f => b[f] === undefined || b[f] === null || b[f] === '');
if (missing.length > 0) {
    msg.statusCode = 400;
    msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
    msg.payload = JSON.stringify({ok: false, error: 'Campos requeridos faltantes: ' + missing.join(', ')});
    return [null, null, msg];
}

// Preparar query de check duplicado
// Duplicado si: mismo hash, o mismo documento+cuit
const hash = b.pdf_hash ? `'${String(b.pdf_hash).replace(/'/g, "''")}'` : 'NULL';
const doc  = b.numerodocumento ? `'${String(b.numerodocumento).replace(/'/g, "''")}'` : 'NULL';
const cuit = b.proveedor_cuit ? `'${String(b.proveedor_cuit).replace(/'/g, "''")}'` : 'NULL';

msg.topic = 'SELECT id FROM staging_facturas WHERE ' +
    `(pdf_hash = ${hash} AND ${hash} !== 'NULL')` +
    ` OR (numerodocumento = ${doc} AND proveedor_cuit = ${cuit} AND ${doc} !== 'NULL')` +
    ' LIMIT 1';
msg.payload = [];
return [msg, null, null];

const dup = msg.payload || [];
if (dup.length > 0) {
    // Ya existe -> 409
    msg.res = msg._res;
    msg.statusCode = 409;
    msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
    msg.payload = JSON.stringify({
        ok: false,
        error: 'Factura duplicada',
        existente_id: dup[0].id
    });
    return [null, msg];
}

// No existe -> preparar INSERT
const f = msg._factura;
const esc = s => s ? String(s).replace(/'/g, "''") : null;
const str = (s) => esc(s) !== null ? `'${esc(s)}'` : 'NULL';
const num = (n) => (n !== null && n !== undefined && !isNaN(Number(n))) ? parseFloat(n) : 0;
const bool = (b) => (b === true || b === 1 || b === '1' || b === 1) ? 1 : 0;

msg.topic = `INSERT INTO staging_facturas (
    id, tipo_operacion, estado_proceso, fecha_carga, usuario_carga, origen,
    numerodocumento, letra, fecha_emision, fecha_vencimiento,
    proveedor_cuit, proveedor_nombre, proveedor_codigo,
    neto, iva_21, iva_105, percepciones, otros_impuestos, total,
    es_dolar, cotizacion, cotizacion_origen, cotizacion_aviso,
    cae, fecha_vto_cae, referencia, nro_remito,
    pdf_filename, pdf_hash, email_origen, email_asunto,
    items_json, confianza_parseo, notas_parseo
) VALUES (
    ${str(f.staging_id)}, ${str(f.tipo_operacion)}, 'PENDIENTE', NOW(), 'n8n', ${str(f.fuente)},
    ${str(f.numerodocumento)}, ${str(f.letra)}, ${str(f.fecha_emision)}, ${str(f.fecha_vencimiento)},
    ${str(f.proveedor_cuit)}, ${str(f.proveedor_nombre)}, ${str(f.proveedor_codigo)},
    ${num(f.neto)}, ${num(f.iva_21)}, ${num(f.iva_105)}, ${num(f.percepciones)}, ${num(f.otros_impuestos)}, ${num(f.total)},
    ${bool(f.es_dolar)}, ${num(f.cotizacion)}, ${str(f.cotizacion_origen)}, ${str(f.cotizacion_aviso)},
    ${str(f.cae)}, ${str(f.fecha_vto_cae)}, ${str(f.referencia)}, ${str(f.nro_remito)},
    ${str(f.pdf_filename)}, ${str(f.pdf_hash)}, ${str(f.email_origen)}, ${str(f.email_asunto)},
    ${str(f.items_json)}, ${str(f.confianza_parseo_label)}, ${str(f.notas_parseo)}
)`;
return [msg, null];

const f = msg._factura;
let items = [];
try { items = JSON.parse(f.items_json || '[]'); } catch(e) { items = []; }

if (!items || items.length === 0) {
    // Sin items -> responder OK directo
    msg.res = msg._res;
    msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
    msg.payload = JSON.stringify({ ok: true, id: f.staging_id, items_inserted: 0 });
    return [null, msg];
}

const esc = s => s ? String(s).replace(/'/g, "''") : '';
const values = items.map(it => {
    const desc = esc(it.descripcion || '');
    const cant = it.cantidad != null ? parseFloat(it.cantidad) : 'NULL';
    const uni  = esc(it.unidad || 'u');
    const pu   = it.precio_unitario != null ? parseFloat(it.precio_unitario) : 'NULL';
    const aliq = it.alicuota_iva != null ? parseInt(it.alicuota_iva) : 'NULL';
    const sub  = it.subtotal != null ? parseFloat(it.subtotal) : 'NULL';
    const lin  = parseInt(it.linea) || 1;
    return `('${esc(f.staging_id)}', ${lin}, '${desc}', ${cant}, '${uni}', ${pu}, ${aliq}, ${sub})`;
}).join(',\n');

msg.topic = `INSERT INTO staging_facturas_items (factura_id, linea, descripcion, cantidad, unidad, precio_unitario, alicuota_iva, subtotal) VALUES\n${values}`;
return [msg, null];

// Formatea respuesta 200 OK despues de insertar items
// (o cuando no habia items que insertar)
msg.res = msg._res;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
const id = (msg._factura && msg._factura.staging_id) || 'unknown';
const inserted = (msg.payload && msg.payload.affectedRows) ? msg.payload.affectedRows : 0;
msg.payload = JSON.stringify({ ok: true, id, items_inserted: inserted });
return msg;
